@Test
public void sanitizeExactly255Chars() {
    StringBuilder input = new StringBuilder();
    for (int i = 0; i < 255; i++) {
        input.append('a');
    }
    String result = ArchiveUtils.sanitize(input.toString());
    assertEquals(255, result.length());
    assertEquals(input.toString(), result);
}

@Test
public void sanitizeExactly256Chars() {
    StringBuilder input = new StringBuilder();
    for (int i = 0; i < 256; i++) {
        input.append('b');
    }
    String result = ArchiveUtils.sanitize(input.toString());
    assertEquals(255, result.length());
    assertTrue(result.endsWith("..."));
    assertEquals(252, result.length() - 3);
}

@Test
public void sanitizeWithControlCharactersAndShortening() {
    StringBuilder input = new StringBuilder();
    for (int i = 0; i < 260; i++) {
        if (i % 10 == 0) {
            input.append('\u0000');
        } else {
            input.append('x');
        }
    }
    String result = ArchiveUtils.sanitize(input.toString());
    assertEquals(255, result.length());
    assertTrue(result.endsWith("..."));
    for (int i = 0; i < 252; i++) {
        char c = result.charAt(i);
        assertTrue(c == '?' || c == 'x');
    }
}

@Test
public void sanitizeEmptyString() {
    String result = ArchiveUtils.sanitize("");
    assertEquals("", result);
}

@Test
public void sanitizeOnlyControlCharacters() {
    String input = "\u0000\u0001\u0002\u0003\u0004";
    String result = ArchiveUtils.sanitize(input);
    assertEquals("?????", result);
}
